  ('fire-eq-tech-moex-02370', 'fire-eq-tech', 'fire-eq-tech-moex-101-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '由燃燒下限分別為7.0%、3.0%的甲、乙兩種氣體組成的混合氣，其中甲氣占70%；若兩氣體不發生催化 或反應，則混合氣之燃燒下限約為：', '["6.5%", "5.8%", "5.0%", "4.5%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "aa1687d2ce7f", "answer_pdf_sha1": "17b1ff966964", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "902", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "火災學概要", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
